#nullable enable // autogenerated

using MukioI18n;
using MVZ2.GameContent.Areas;
using MVZ2.Vanilla.Audios;
using MVZ2.Vanilla.Definitions;
using MVZ2.Vanilla.Localization;
using MVZ2.Vanilla.RandomChina;
using MVZ2Logic.Entities;
using PVZEngine.Entities;
using Tools;

namespace MVZ2.GameContent.RandomChinaEvents
{
    [RandomChinaEventDefinition(VanillaRandomChinaEventNames.bindingChains)]
    public class BindingChainsEvent : RandomChinaEventDefinition
    {
        public BindingChainsEvent(string nsp, string path) : base(nsp, path, NAME, DESCRIPTION)
        {
        }
        public override void Run(Entity contraption, RandomGenerator rng)
        {
            var level = contraption.Level;
            var seedPacks = Palace.GetBlueprintsToLock(level);
            Palace.LockRandomBlueprints(level, seedPacks, 3, rng);
            contraption.PlaySound(VanillaSoundID.locked);
        }
        [TranslateMsg("随机瓷器事件名称", VanillaStrings.CONTEXT_RANDOM_CHINA_EVENT_NAME)]
        public const string NAME = "魂缚锁链";
        [TranslateMsg("随机瓷器事件描述", VanillaStrings.CONTEXT_RANDOM_CHINA_EVENT_DESCRIPTION)]
        public const string DESCRIPTION = "暂时锁定随机3个蓝图";
    }
}
